348		if err != nil {
349			return "", false, err
350		}
351	
352		active := resolveActiveBranch(data)
353	
354		var lastAssistantText string
355		scanner := newJSONLScanner(data)
356		for scanner.Scan() {
357			var entry messageEntry
358			if err := json.Unmarshal(scanner.Bytes(), &entry); err != nil {
359				continue
360			}
361			if entry.Type != entryTypeMessage || entry.Message.Role != "assistant" {
362				continue
363			}
364			if active != nil && !active[entry.ID] {
365				continue
366			}
367	
368			var items []contentItem
369			if err := json.Unmarshal(entry.Message.Content, &items); err != nil {
370				continue
371			}
372	
373			for _, item := range items {
374				if item.Type == "text" && item.Text != "" {
375					lastAssistantText = item.Text
376				}
377			}
378		}
379	
380		if lastAssistantText != "" {
381			return lastAssistantText, true, nil
382		}
383		return "", false, nil
384	}
