386	func (a *Agent) CalculateTokens(data []byte, offset int) (protocol.TokenUsageResponse, error) {
387		active := resolveActiveBranch(data)
388	
389		content := skipLines(data, offset)
390	
391		var result protocol.TokenUsageResponse
392		scanner := newJSONLScanner(content)
393		for scanner.Scan() {
394			var entry messageEntry
395			if err := json.Unmarshal(scanner.Bytes(), &entry); err != nil {
396				continue
397			}
398			if entry.Type != entryTypeMessage || entry.Message.Role != "assistant" || entry.Message.Usage == nil {
399				continue
400			}
401			if active != nil && !active[entry.ID] {
402				continue
403			}
404	
405			result.InputTokens += entry.Message.Usage.Input
406			result.OutputTokens += entry.Message.Usage.Output
407			result.CacheReadTokens += entry.Message.Usage.CacheRead
408			result.CacheCreationTokens += entry.Message.Usage.CacheWrite
409			result.APICallCount++
410		}
411	
412		return result, nil
413	}
