1	package pi
2	
3	import (
4		"bytes"
5		"encoding/base64"
6		"encoding/json"
7		"errors"
8		"fmt"
9		"os"
10		"strings"
11	
12		"github.com/entireio/external-agents/agents/entire-agent-pi/internal/protocol"
13	)
14	
15	const (
16		compactTranscriptAgent      = "pi"
17		compactTranscriptCLIVersion = "unknown"
18		compactContentTypeText      = "text"
19		compactToolResultSuccess    = "success"
20		compactToolResultError      = "error"
21	)
22	
23	var compactToolNameMap = map[string]string{
24		"edit":  "Edit",
25		"read":  "Read",
26		"write": "Write",
27	}
28	
29	type compactTranscriptLine struct {
30		V            int    `json:"v"`
31		Agent        string `json:"agent"`
32		CLIVersion   string `json:"cli_version"`
33		Type         string `json:"type"`
34		TS           string `json:"ts,omitempty"`
35		ID           string `json:"id,omitempty"`
36		InputTokens  int    `json:"input_tokens,omitempty"`
37		OutputTokens int    `json:"output_tokens,omitempty"`
38		Content      any    `json:"content"`
39	}
40	
41	type compactUserTextBlock struct {
42		Text string `json:"text"`
43	}
44	
45	type compactAssistantTextBlock struct {
46		Type string `json:"type"`
47		Text string `json:"text"`
48	}
49	
50	type compactAssistantToolUseBlock struct {
51		Type   string                 `json:"type"`
52		ID     string                 `json:"id,omitempty"`
53		Name   string                 `json:"name"`
54		Input  any                    `json:"input"`
55		Result *compactToolResultJSON `json:"result,omitempty"`
56	}
57	
58	type compactToolResultJSON struct {
59		Output string `json:"output"`
60		Status string `json:"status"`
61	}
62	
63	func (a *Agent) CompactTranscript(sessionRef string) (protocol.CompactTranscriptResponse, error) {
64		data, err := os.ReadFile(sessionRef)
65		if err != nil {
66			return protocol.CompactTranscriptResponse{}, fmt.Errorf("failed to read transcript: %w", err)
67		}
68	
69		compacted, err := compactTranscriptBytes(data)
70		if err != nil {
71			return protocol.CompactTranscriptResponse{}, err
72		}
73	
74		return protocol.CompactTranscriptResponse{
75			Transcript: base64.StdEncoding.EncodeToString(compacted),
76		}, nil
77	}
78	
79	func compactTranscriptBytes(data []byte) ([]byte, error) {
80		active := resolveActiveBranch(data)
81		results, err := collectCompactToolResults(data, active)
82		if err != nil {
83			return nil, err
84		}
85	
86		cliVersion := compactCLIVersion()
87		var buf bytes.Buffer
88	
89		scanner := newJSONLScanner(data)
90		for scanner.Scan() {
91			var entry messageEntry
92			if err := json.Unmarshal(scanner.Bytes(), &entry); err != nil {
93				continue
94			}
95			if entry.Type != entryTypeMessage {
96				continue
97			}
98			if active != nil && !active[entry.ID] {
99				continue
100			}
101	
